{"version":3,"names":["resolve","styleProp","cleanedProps","StyleSheet","Symbol","iterator","Object","assign"],"sources":["resolve.ts"],"sourcesContent":["import { StyleSheet } from 'react-native';\n\n// Kept in separate file, to avoid name collision with Symbol element\nexport function resolve<T>(styleProp: Iterable<T>, cleanedProps: T) {\n  if (styleProp) {\n    return StyleSheet\n      ? [styleProp, cleanedProps]\n      : // Compatibility for arrays of styles in plain react web\n      styleProp[Symbol.iterator]\n      ? Object.assign({}, ...styleProp, cleanedProps)\n      : Object.assign({}, styleProp, cleanedProps);\n  } else {\n    return cleanedProps;\n  }\n}\n"],"mappings":"wVAAA,yCAGO,QAASA,QAAT,CAAoBC,SAApB,CAA4CC,YAA5C,CAA6D,CAClE,GAAID,SAAJ,CAAe,CACb,MAAOE,wBAAA,CACH,CAACF,SAAD,CAAYC,YAAZ,CADG,CAGLD,SAAS,CAACG,MAAM,CAACC,QAAR,CAAT,CACEC,MAAM,CAACC,MAAP,OAAAD,MAAM,EAAQ,EAAR,yCAAeL,SAAf,GAA0BC,YAA1B,GADR,CAEE,sBAAc,EAAd,CAAkBD,SAAlB,CAA6BC,YAA7B,CALJ,CAMD,CAPD,IAOO,CACL,MAAOA,aAAP,CACD,CACF"}
